    82→### 2.3 Create `backend/src/types/index.ts`
    83→
    84→```typescript
    85→export interface Session {
    86→  id: string;
    87→  name: string;
    88→  status: 'starting' | 'ready' | 'busy' | 'error' | 'terminated';
    89→  workingDirectory: string;
    90→  cliProcess?: any;
    91→  createdAt: Date;
    92→  lastActivity: Date;
    93→  commandsExecuted: number;
    94→}
    95→
    96→export interface HookEvent {
    97→  session_id: string;
    98→  transcript_path: string;
    99→  hook_event_name: string;
