   321→### 2.6 Create `backend/src/server.ts`
   322→
   323→```typescript
   324→import express from 'express';
   325→import { createServer } from 'http';
   326→import { WebSocketServer } from 'ws';
   327→import { SessionManager } from './services/SessionManager';
   328→import { setupDashboardSocket } from './websocket/DashboardSocket';
   329→import type { CreateSessionRequest, CommandRequest } from './types';
   330→
   331→const app = express();
   332→app.use(express.json());
   333→
   334→const server = createServer(app);
   335→const wss = new WebSocketServer({ server, path: '/ws' });
   336→
   337→const sessionManager = new SessionManager();
   338→setupDashboardSocket(wss, sessionManager);
   339→
   340→// Routes
   341→
   342→// Create session
   343→app.post('/api/session', async (req, res) => {
   344→  try {
   345→    const options: CreateSessionRequest = req.body;
   346→    const session = await sessionManager.createSession(options);
   347→    res.json(session);
   348→  } catch (err: any) {
   349→    res.status(500).json({ error: err.message });
   350→  }
   351→});
   352→
   353→// List sessions
   354→app.get('/api/session', (_req, res) => {
   355→  res.json(sessionManager.getAllSessions());
   356→});
   357→
   358→// Get session
   359→app.get('/api/session/:id', (req, res) => {
   360→  const session = sessionManager.getSession(req.params.id);
   361→  if (!session) {
   362→    return res.status(404).json({ error: 'Session not found' });
   363→  }
   364→  res.json(session);
   365→});
   366→
   367→// Send command
   368→app.post('/api/session/:id/command', (req, res) => {
   369→  try {
   370→    const { command } = req.body as CommandRequest;
   371→    sessionManager.sendCommand(req.params.id, command);
   372→    res.json({ success: true });
   373→  } catch (err: any) {
   374→    res.status(400).json({ error: err.message });
   375→  }
   376→});
   377→
   378→// Terminate session
   379→app.delete('/api/session/:id', (req, res) => {
   380→  sessionManager.terminateSession(req.params.id);
   381→  res.json({ success: true });
   382→});
   383→
   384→// Hook events endpoint (for VoiceProxy.hook.ts)
   385→app.post('/api/hooks/event', (req, res) => {
   386→  sessionManager.handleHookEvent(req.body);
   387→  res.json({ received: true });
   388→});
   389→
   390→// Health check
   391→app.get('/health', (_req, res) => {
   392→  res.json({
   393→    status: 'healthy',
   394→    timestamp: new Date().toISOString(),
   395→    sessions: {
   396→      active: sessionManager.getAllSessions().filter(s => s.status !== 'terminated').length
   397→    }
   398→  });
   399→});
   400→
   401→const PORT = process.env.PORT || 3000;
   402→server.listen(PORT, () => {
   403→  console.log(`Voice Claude Code backend running on port ${PORT}`);
   404→});
   405→```
