   437→## Step 3: Claude Code Hook (15 minutes)
   438→
   439→### 3.1 Create `hooks/VoiceProxy.hook.ts`
   440→
   441→```typescript
   442→#!/usr/bin/env bun
   443→/**
   444→ * VoiceProxy.hook.ts - Forwards Claude Code events to voice backend
   445→ *
   446→ * TRIGGER: All hook events
   447→ * INPUT: JSON via stdin
   448→ * OUTPUT: HTTP POST to backend
   449→ * EXIT: Always 0 (allow)
   450→ */
   451→
   452→const BACKEND_URL = process.env.VOICE_BACKEND_URL || 'http://localhost:3000';
   453→
   454→async function main() {
   455→  try {
   456→    // Read stdin
   457→    const stdin = await Bun.stdin.text();
   458→    if (!stdin.trim()) {
   459→      process.exit(0);
   460→    }
   461→
   462→    const event = JSON.parse(stdin);
   463→
   464→    // Forward to backend (don't await, fire and forget)
   465→    fetch(`${BACKEND_URL}/api/hooks/event`, {
   466→      method: 'POST',
   467→      headers: { 'Content-Type': 'application/json' },
   468→      body: JSON.stringify({
   469→        ...event,
   470→        receivedAt: new Date().toISOString(),
   471→        sessionId: process.env.CLAUDE_SESSION_ID || 'unknown'
   472→      }),
   473→      signal: AbortSignal.timeout(1000) // 1s timeout
   474→    }).catch(err => {
   475→      // Log but don't fail
   476→      console.error('Hook delivery failed:', err.message);
   477→    });
   478→
   479→    // Always allow
   480→    process.exit(0);
   481→  } catch (err) {
   482→    console.error('Hook error:', err);
   483→    process.exit(0); // Don't block Claude on hook errors
   484→  }
   485→}
   486→
   487→main();
   488→```
