   593→### 4.4 Create `agent/llm/gemini.py`
   594→
   595→```python
   596→import google.generativeai as genai
   597→from ..config import Config
   598→
   599→genai.configure(api_key=Config.GOOGLE_API_KEY)
   600→
   601→INTENT_PROMPT = """
   602→You are a command interpreter for voice-controlled Claude Code.
   603→
   604→Classify the user's intent and extract parameters.
   605→
   606→Intents:
   607→- createSession: Create a new Claude Code session
   608→- sendCommand: Send a command to the current session
   609→- listSessions: List all active sessions
   610→- terminateSession: Terminate current session
   611→- switchSession: Switch to a different session
   612→
   613→Return JSON only: {"intent": "...", "params": {...}}
   614→
   615→Examples:
   616→- "create a new session for the api project" → {"intent": "createSession", "params": {"name": "api"}}
   617→- "list all files" → {"intent": "sendCommand", "params": {"command": "list all files"}}
   618→- "what sessions are running" → {"intent": "listSessions", "params": {}}
   619→"""
   620→
   621→class IntentRecognizer:
   622→    def __init__(self):
   623→        self.model = genai.GenerativeModel(
   624→            'gemini-2.0-flash-exp',
   625→            generation_config={
   626→                "temperature": 0.1,
   627→                "max_output_tokens": 200,
   628→            }
   629→        )
   630→
   631→    async def recognize(self, text: str) -> dict:
   632→        prompt = f"{INTENT_PROMPT}\n\nUser input: {text}"
   633→        response = await self.model.generate_content_async(prompt)
   634→        result = response.text.strip()
   635→
   636→        # Extract JSON from response
   637→        import json
   638→        try:
   639→            if "```json" in result:
   640→                result = result.split("```json")[1].split("```")[0].strip()
   641→            elif "```" in result:
   642→                result = result.split("```")[1].split("```")[0].strip()
   643→            return json.loads(result)
   644→        except:
   645→            # Default to sendCommand if parsing fails
   646→            return {"intent": "sendCommand", "params": {"command": text}}
   647→```
