   726→### 4.7 Create `agent/voice_agent.py`
   727→
   728→```python
   729→import asyncio
   730→import json
   731→from livekit import rtc
   732→from livekit.agents import AutoSubscribe, JobContext, WorkerOptions, cli
   733→from livekit.plugins import deepgram, cartesia
   734→
   735→from .config import Config
   736→from .llm.gemini import IntentRecognizer
   737→import aiohttp
   738→
   739→class VoiceAgent:
   740→    def __init__(self):
   741→        self.intent_recognizer = IntentRecognizer()
   742→        self.backend_url = Config.BACKEND_URL
   743→        self.current_session_id = None
   744→
   745→    async def send_to_backend(self, intent: str, params: dict):
   746→        """Send intent to backend"""
   747→        async with aiohttp.ClientSession() as session:
   748→            if intent == "createSession":
   749→                async with session.post(
   750→                    f"{self.backend_url}/api/session",
   751→                    json=params
   752→                ) as resp:
   753→                    return await resp.json()
   754→            elif intent == "sendCommand":
   755→                if not self.current_session_id:
   756→                    return {"error": "No active session"}
   757→                async with session.post(
   758→                    f"{self.backend_url}/api/session/{self.current_session_id}/command",
   759→                    json={"command": params.get("command", "")}
   760→                ) as resp:
   761→                    return await resp.json()
   762→            elif intent == "listSessions":
   763→                async with session.get(f"{self.backend_url}/api/session") as resp:
   764→                    return await resp.json()
   765→            elif intent == "switchSession":
   766→                sessions = await self.list_sessions()
   767→                for s in sessions:
   768→                    if s.get("name") == params.get("name"):
   769→                        self.current_session_id = s.get("id")
   770→                        return {"switched_to": s.get("name")}
   771→                return {"error": "Session not found"}
   772→
   773→async def entrypoint(ctx: JobContext):
   774→    agent = VoiceAgent()
   775→
   776→    # Connect to microphone
   777→    source = rtc.AudioSource(ctx.room)
   778→    stream = AudioStream(source)
   779→
   780→    @ctx.room.on("participant_connected")
   781→    def on_participant_connected(participant):
   782→        print(f"Participant connected: {participant.identity}")
   783→
   784→    # STT setup
   785→    stt = deepgram.STT()
   786→    stt_stream = stt.stream()
   787→
   788→    # TTS setup
   789→    tts = cartesia.TTS()
   790→    tts_stream = tts.stream()
   791→
   792→    async def process_audio():
   793→        async for event in stt_stream:
   794→            if event.type == "final_transcript":
   795→                text = event.alternatives[0].text
   796→                print(f"User said: {text}")
   797→
   798→                # Recognize intent
   799→                intent_result = await agent.intent_recognizer.recognize(text)
   800→                print(f"Intent: {intent_result}")
   801→
   802→                # Execute intent
   803→                response = await agent.send_to_backend(
   804→                    intent_result["intent"],
   805→                    intent_result.get("params", {})
   806→                )
   807→
   808→                # Generate response
   809→                response_text = generate_response_text(response)
   810→                tts_stream.push_text(response_text)
   811→
   812→    # Start processing
   813→    await asyncio.gather(
   814→        process_audio(),
   815→        handle_room_audio(ctx.room, source, stt_stream),
   816→        play_tts_audio(ctx.room, tts_stream)
   817→    )
   818→
   819→def generate_response_text(response: dict) -> str:
   820→    """Generate spoken response from backend response"""
   821→    if "error" in response:
   822→        return f"Sorry, {response['error']}"
   823→    if "id" in response:
   824→        return "Session created and ready"
   825→    if "name" in response and len(response) == 1:
   826→        return f"Switched to {response['name']}"
   827→    return "Done"
   828→
   829→async def handle_room_audio(room, source, stt_stream):
   830→    """Handle audio from room"""
   831→    @room.on("track_subscribed")
   832→    def on_track_subscribed(track, publication, participant):
   833→        if track.kind == rtc.TrackKind.KIND_AUDIO:
   834→            async for frame in track:
   835→                stt_stream.push_frame(frame)
   836→
   837→async def play_tts_audio(room, tts_stream):
   838→    """Play TTS audio to room"""
   839→    async for audio in tts_stream:
   840→        await room.local_participant.publish_audio(audio)
   841→
   842→if __name__ == "__main__":
   843→    cli.run_app(WorkerOptions(entrypoint=entrypoint))
   844→```
