  id: string;
  name: string;
  status: 'starting' | 'ready' | 'busy' | 'error' | 'terminated';
  workingDirectory: string;
  cliProcess?: any;
  createdAt: Date;
  lastActivity: Date;
  commandsExecuted: number;
}

export interface HookEvent {
  session_id: string;
  transcript_path: string;
  hook_event_name: string;
  prompt?: string;
  tool_name?: string;
  tool_input?: Record<string, any>;
  response?: string;
  timestamp: string;
}

export interface CommandRequest {
  sessionId: string;
  command: string;
  voice?: boolean;
}

export interface CreateSessionRequest {
  name?: string;
  workingDirectory?: string;
}

import { v4 as uuidv4 } from 'uuid';
import * as pty from 'node-pty';
import * as fs from 'fs/promises';
import * as path from 'path';
import { EventEmitter } from 'events';
import type { Session } from '../types';

export class SessionManager extends EventEmitter {
  private sessions: Map<string, Session> = new Map();
  private workspacesDir = path.join(process.cwd(), 'workspaces');

  async createSession(options: { name?: string } = {}): Promise<Session> {
    const id = uuidv4();
    const name = options.name || `session-${id.slice(0, 8)}`;
    const workDir = path.join(this.workspacesDir, id);

    // Create workspace directory
    await fs.mkdir(workDir, { recursive: true });

    // Spawn Claude Code CLI
    const cliProcess = this.spawnClaudeCode(id, workDir);

    const session: Session = {
      id,
      name,
      status: 'starting',
      workingDirectory: workDir,
      cliProcess,
      createdAt: new Date(),
      lastActivity: new Date(),
      commandsExecuted: 0
    };

    this.sessions.set(id, session);

    // Wait for CLI to be ready
    cliProcess.onData((data: string) => {
      if (data.includes('Enter a command') || data.includes('How can I help')) {
        session.status = 'ready';
        this.emit('session:ready', session);
      }
      // Emit all output for dashboard
      this.emit('session:output', { sessionId: id, data });
    });

    this.emit('session:created', session);
    return session;
  }

  private spawnClaudeCode(sessionId: string, workDir: string) {
    const cli = pty.spawn('claude', ['-p', '--output-format', 'json'], {
      name: 'xterm-color',
      cols: 80,
      rows: 24,
      cwd: workDir,
      env: {
        ...process.env,
        CLAUDE_SESSION_ID: sessionId,
        CLAUDE_HOOKS_ENABLED: 'true'
      }
    });

    cli.onExit(({ exitCode }) => {
      const session = this.sessions.get(sessionId);
      if (session) {
        session.status = 'terminated';
        this.emit('session:terminated', { sessionId, exitCode });
      }
    });

    return cli;
  }

  sendCommand(sessionId: string, command: string): void {
    const session = this.sessions.get(sessionId);
    if (!session || session.status === 'terminated') {
      throw new Error(`Session ${sessionId} not found or terminated`);
    }

    session.cliProcess?.write(command + '\n');
    session.status = 'busy';
    session.lastActivity = new Date();
    session.commandsExecuted++;

    this.emit('session:busy', session);
  }

  terminateSession(sessionId: string): void {
    const session = this.sessions.get(sessionId);
    if (!session) return;

    session.cliProcess?.kill();
    session.status = 'terminated';
    this.emit('session:terminated', { sessionId });
  }

  getSession(sessionId: string): Session | undefined {
    return this.sessions.get(sessionId);
  }

  getAllSessions(): Session[] {
    return Array.from(this.sessions.values());
  }

  handleHookEvent(event: any): void {
    const session = this.sessions.get(event.session_id);
    if (!session) return;

    this.emit('session:hook', { sessionId: event.session_id, event });

    // Update status based on hook
    if (event.hook_event_name === 'Stop' && session.status === 'busy') {
      session.status = 'ready';
      this.emit('session:ready', session);
    }
  }
}

import { Server as WebSocketServer } from 'ws';
import { SessionManager } from '../services/SessionManager';
import type { Session } from '../types';

export function setupDashboardSocket(wss: WebSocketServer, sessionManager: SessionManager) {
  // Forward session events to all dashboard clients
  sessionManager.on('session:created', (session: Session) => {
    broadcast({ type: 'session:created', session });
  });

  sessionManager.on('session:ready', (session: Session) => {
    broadcast({ type: 'session:updated', session });
  });

  sessionManager.on('session:busy', (session: Session) => {
    broadcast({ type: 'session:updated', session });
  });

  sessionManager.on('session:terminated', ({ sessionId }) => {
    broadcast({ type: 'session:terminated', sessionId });
  });

  sessionManager.on('session:output', ({ sessionId, data }) => {
    broadcast({ type: 'session:output', sessionId, data });
  });

  sessionManager.on('session:hook', ({ sessionId, event }) => {
    broadcast({ type: 'session:hook', sessionId, event });
  });

  wss.on('connection', (ws) => {
    console.log('Dashboard client connected');

    // Send current sessions on connect
    ws.send(JSON.stringify({
      type: 'init',
      sessions: sessionManager.getAllSessions()
    }));

    ws.on('message', (data) => {
      try {
        const msg = JSON.parse(data.toString());
        handleClientMessage(ws, msg, sessionManager);
      } catch (err) {
        console.error('Invalid message:', err);
      }
    });

    ws.on('close', () => {
      console.log('Dashboard client disconnected');
    });
  });

  function broadcast(message: any) {
    wss.clients.forEach((client) => {
      if (client.readyState === 1) { // OPEN
        client.send(JSON.stringify(message));
      }
    });
  }

  function handleClientMessage(ws: any, msg: any, sessionManager: SessionManager) {
    switch (msg.type) {
      case 'subscribe':
        // Handle session-specific subscriptions
        break;
      case 'command':
        sessionManager.sendCommand(msg.sessionId, msg.command);
        break;
      case 'terminate':
        sessionManager.terminateSession(msg.sessionId);
        break;
    }
  }
}

import express from 'express';
import { createServer } from 'http';
import { WebSocketServer } from 'ws';
import { SessionManager } from './services/SessionManager';
import { setupDashboardSocket } from './websocket/DashboardSocket';
import type { CreateSessionRequest, CommandRequest } from './types';

const app = express();
app.use(express.json());

const server = createServer(app);
const wss = new WebSocketServer({ server, path: '/ws' });

const sessionManager = new SessionManager();
setupDashboardSocket(wss, sessionManager);

// Routes

// Create session
app.post('/api/session', async (req, res) => {
  try {
    const options: CreateSessionRequest = req.body;
    const session = await sessionManager.createSession(options);
    res.json(session);
  } catch (err: any) {
    res.status(500).json({ error: err.message });
  }
});

// List sessions
app.get('/api/session', (_req, res) => {
  res.json(sessionManager.getAllSessions());
});

// Get session
app.get('/api/session/:id', (req, res) => {
  const session = sessionManager.getSession(req.params.id);
  if (!session) {
    return res.status(404).json({ error: 'Session not found' });
  }
  res.json(session);
});

// Send command
app.post('/api/session/:id/command', (req, res) => {
  try {
    const { command } = req.body as CommandRequest;
    sessionManager.sendCommand(req.params.id, command);
    res.json({ success: true });
  } catch (err: any) {
    res.status(400).json({ error: err.message });
  }
});

// Terminate session
app.delete('/api/session/:id', (req, res) => {
  sessionManager.terminateSession(req.params.id);
  res.json({ success: true });
});

// Hook events endpoint (for VoiceProxy.hook.ts)
app.post('/api/hooks/event', (req, res) => {
  sessionManager.handleHookEvent(req.body);
  res.json({ received: true });
});

// Health check
app.get('/health', (_req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    sessions: {
      active: sessionManager.getAllSessions().filter(s => s.status !== 'terminated').length
    }
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Voice Claude Code backend running on port ${PORT}`);
});

