import google.generativeai as genai
from ..config import Config

genai.configure(api_key=Config.GOOGLE_API_KEY)

INTENT_PROMPT = """
You are a command interpreter for voice-controlled Claude Code.

Classify the user's intent and extract parameters.

Intents:
- createSession: Create a new Claude Code session
- sendCommand: Send a command to the current session
- listSessions: List all active sessions
- terminateSession: Terminate current session
- switchSession: Switch to a different session

Return JSON only: {"intent": "...", "params": {...}}

Examples:
- "create a new session for the api project" -> {"intent": "createSession", "params": {"name": "api"}}
- "list all files" -> {"intent": "sendCommand", "params": {"command": "list all files"}}
- "what sessions are running" -> {"intent": "listSessions", "params": {}}
"""

class IntentRecognizer:
    def __init__(self):
        self.model = genai.GenerativeModel(
            'gemini-2.0-flash-exp',
            generation_config={
                "temperature": 0.1,
                "max_output_tokens": 200,
            }
        )

    async def recognize(self, text: str) -> dict:
        prompt = f"{INTENT_PROMPT}\n\nUser input: {text}"
        response = await self.model.generate_content_async(prompt)
        result = response.text.strip()

        # Extract JSON from response
        import json
        try:
            if "```json" in result:
                result = result.split("```json")[1].split("```")[0].strip()
            elif "```" in result:
                result = result.split("```")[1].split("```")[0].strip()
            return json.loads(result)
        except:
            # Default to sendCommand if parsing fails
            return {"intent": "sendCommand", "params": {"command": text}}
EOF

