import { useState, useEffect } from 'react';
import { io, Socket } from 'socket.io-client';
import './App.css';

interface Session {
  id: string;
  name: string;
  status: string;
  createdAt: string;
  commandsExecuted: number;
}

function App() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [output, setOutput] = useState<string[]>([]);
  const [socket, setSocket] = useState<Socket | null>(null);
  const [wsConnected, setWsConnected] = useState(false);

  useEffect(() => {
    const ws = io('http://localhost:3000');

    ws.on('connect', () => {
      console.log('Connected to dashboard');
      setWsConnected(true);
    });

    ws.on('disconnect', () => {
      setWsConnected(false);
    });

    ws.on('init', (data: { sessions: Session[] }) => {
      setSessions(data.sessions);
    });

    ws.on('session:created', (data: { session: Session }) => {
      setSessions(prev => [...prev, data.session]);
    });

    ws.on('session:updated', (data: { session: Session }) => {
      setSessions(prev => prev.map(s => s.id === data.session.id ? data.session : s));
    });

    ws.on('session:output', (data: { sessionId: string; data: string }) => {
      if (selectedSession && data.sessionId === selectedSession.id) {
        setOutput(prev => [...prev, data.data]);
      }
    });

    ws.on('session:terminated', (data: { sessionId: string }) => {
      setSessions(prev => prev.filter(s => s.id !== data.sessionId));
      if (selectedSession?.id === data.sessionId) {
        setSelectedSession(null);
        setOutput([]);
      }
    });

    setSocket(ws);

    return () => {
      ws.disconnect();
    };
  }, [selectedSession]);

  const createSession = async () => {
    await fetch('http://localhost:3000/api/session', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({})
    });
  };

  const terminateSession = async (id: string) => {
    await fetch(`http://localhost:3000/api/session/${id}`, {
      method: 'DELETE'
    });
  };

  const sendCommand = async (command: string) => {
    if (!selectedSession) return;
    await fetch(`http://localhost:3000/api/session/${selectedSession.id}/command`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ command })
    });
  };

  return (
    <div className="app">
      <header>
        <h1>Voice-Controlled Claude Code</h1>
        <div className="header-actions">
          <span className={`connection-status ${wsConnected ? 'connected' : 'disconnected'}`}>
            {wsConnected ? '● Connected' : '○ Disconnected'}
          </span>
          <button onClick={createSession}>+ New Session</button>
        </div>
      </header>

      <main>
        <div className="sessions-panel">
          <h2>Sessions</h2>
          {sessions.length === 0 ? (
            <div className="empty-sessions">No active sessions</div>
          ) : (
            sessions.map(session => (
              <div
                key={session.id}
                className={`session-card ${selectedSession?.id === session.id ? 'active' : ''}`}
                onClick={() => {
                  setSelectedSession(session);
                  setOutput([]);
                }}
              >
                <h3>{session.name}</h3>
                <span className={`status status-${session.status}`}>{session.status}</span>
                <span className="commands">{session.commandsExecuted} commands</span>
                <button
                  className="terminate-btn"
                  onClick={(e) => { e.stopPropagation(); terminateSession(session.id); }}
                >
                  Stop
                </button>
              </div>
            ))
          )}
        </div>

        <div className="session-panel">
          {selectedSession ? (
            <>
              <div className="session-header">
                <h2>{selectedSession.name}</h2>
                <span className={`status status-${selectedSession.status}`}>
                  {selectedSession.status}
                </span>
              </div>

              <div className="command-bar">
                <input
                  type="text"
                  placeholder="Enter command..."
                  onKeyPress={(e) => {
                    if (e.key === 'Enter') {
                      sendCommand((e.target as HTMLInputElement).value);
                      (e.target as HTMLInputElement).value = '';
                    }
                  }}
                />
                <button className="voice-btn">Voice</button>
              </div>

              <div className="output">
                {output.length === 0 ? (
                  <div className="empty-output">Waiting for output...</div>
                ) : (
                  output.map((line, i) => (
                    <div key={i} className="output-line">{line}</div>
                  ))
                )}
              </div>
            </>
          ) : (
            <div className="empty-state">Select a session to view</div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;

