.header-actions {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.connection-status {
  font-size: 0.875rem;
}

.connection-status.connected {
  color: #22c55e;
}

.connection-status.disconnected {
  color: #ef4444;
}

header button {
  padding: 0.5rem 1rem;
  background: #3b82f6;
  color: white;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 500;
}

header button:hover {
  background: #2563eb;
}

main {
  display: grid;
  grid-template-columns: 300px 1fr;
  overflow: hidden;
}

.sessions-panel {
  background: #0d0d0d;
  padding: 1rem;
  overflow-y: auto;
  border-right: 1px solid #333;
}

.sessions-panel h2 {
  color: white;
  font-size: 1rem;
  margin: 0 0 1rem 0;
}

.empty-sessions {
  color: #6b7280;
  font-size: 0.875rem;
  text-align: center;
  padding: 2rem 0;
}

.session-card {
  background: #1a1a1a;
  padding: 1rem;
  margin-bottom: 0.5rem;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.2s;
  border: 1px solid transparent;
}

.session-card:hover {
  background: #252525;
}

.session-card.active {
  border-color: #3b82f6;
  background: #1e293b;
}

.session-card h3 {
  margin: 0 0 0.5rem 0;
  color: white;
  font-size: 0.9rem;
}

.session-card > * {
  display: block;
  margin-bottom: 0.25rem;
}

.status {
  display: inline-block;
  padding: 0.125rem 0.5rem;
  border-radius: 12px;
  font-size: 0.7rem;
  text-transform: uppercase;
  font-weight: 600;
}

.status-ready { background: #22c55e; color: white; }
.status-busy { background: #f59e0b; color: white; }
.status-starting { background: #3b82f6; color: white; }
.status-terminated { background: #6b7280; color: white; }
.status-error { background: #ef4444; color: white; }

.commands {
  font-size: 0.75rem;
  color: #9ca3af;
}

.terminate-btn {
  margin-top: 0.5rem;
  padding: 0.25rem 0.5rem;
  font-size: 0.75rem;
  background: #ef4444;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  width: 100%;
}

.terminate-btn:hover {
  background: #dc2626;
}

.session-panel {
  display: flex;
  flex-direction: column;
  background: #0d0d0d;
}

.session-header {
  padding: 1rem 2rem;
  border-bottom: 1px solid #333;
  display: flex;
  align-items: center;
  gap: 1rem;
}

.session-header h2 {
  margin: 0;
  color: white;
  font-size: 1rem;
}

.command-bar {
  padding: 1rem 2rem;
  display: flex;
  gap: 0.5rem;
  border-bottom: 1px solid #333;
}

.command-bar input {
  flex: 1;
  padding: 0.5rem 1rem;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 6px;
  color: white;
  font-family: inherit;
}

.command-bar input:focus {
  outline: none;
  border-color: #3b82f6;
}

.voice-btn {
  padding: 0.5rem 1.5rem;
  background: #8b5cf6;
  color: white;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 500;
}

.voice-btn:hover {
  background: #7c3aed;
}

.output {
  flex: 1;
  padding: 1rem 2rem;
  overflow-y: auto;
  font-family: 'Consolas', 'Monaco', monospace;
  font-size: 0.875rem;
  color: #e5e7eb;
}

.output-line {
  white-space: pre-wrap;
  margin-bottom: 0.25rem;
  line-height: 1.5;
}

.empty-output {
  color: #6b7280;
  text-align: center;
  padding: 2rem;
}

.empty-state {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: #6b7280;
  font-size: 1.125rem;
}

#root {
  height: 100vh;
}

body {
  margin: 0;
  padding: 0;
}

